const crypto = require('crypto');
const config = $('Configuration (EDIT ME)').first().json;
const item = $input.first();

const signatureHeader = (item.json.headers && item.json.headers['x-wc-webhook-signature']) || '';
const rawBody = item.binary && item.binary.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf8')
  : JSON.stringify(item.json.body || {});

const expected = crypto.createHmac('sha256', config.webhookSecret).update(rawBody).digest('base64');

let valid = false;
if (signatureHeader && expected.length === signatureHeader.length) {
  valid = crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(signatureHeader));
}

return [{ json: { valid, body: JSON.parse(rawBody) } }];

// Transform WooCommerce order to KSeF invoice format
const order = $input.first().json.body;
const config = $('Configuration (EDIT ME)').first().json;

// Extract NIP from billing fields or meta_data
const nipField = (order.meta_data || []).find(m => m.key === '_billing_nip' || m.key === 'billing_nip');
const buyerNip = nipField?.value || '';

if (!buyerNip) {
  // No NIP = consumer (osoba fizyczna), skip KSeF
  return [{ json: { skip: true, reason: 'No buyer NIP - consumer purchase, KSeF not required' } }];
}

// Map WooCommerce line items to KSeF items
const items = (order.line_items || []).map(item => {
  const netTotal = parseFloat(item.total) || 0;
  const taxTotal = parseFloat(item.total_tax) || 0;
  const quantity = item.quantity || 1;
  const unitPrice = Math.round((netTotal / quantity) * 100) / 100;

  // Detect VAT rate from tax amount
  let vatRate = 23; // default
  if (netTotal > 0) {
    const rate = Math.round((taxTotal / netTotal) * 100);
    if ([23, 8, 5, 0].includes(rate)) vatRate = rate;
  }

  return {
    name: item.name,
    quantity: quantity,
    unitPrice: unitPrice,
    vatRate: vatRate
  };
});

const today = new Date().toISOString().split('T')[0];

const invoice = {
  invoiceNumber: `WOO/${order.number || order.id}`,
  issueDate: today,
  saleDate: order.date_created?.split('T')[0] || today,
  issuePlace: order.billing?.city || 'Warszawa',
  currency: order.currency || 'PLN',
  type: 'VAT',
  seller: {
    nip: config.sellerNip,
    name: config.sellerName,
    address: {
      street: config.sellerStreet,
      city: config.sellerCity
    }
  },
  buyer: {
    nip: buyerNip,
    name: order.billing?.company || `${order.billing?.first_name} ${order.billing?.last_name}`,
    address: {
      street: order.billing?.address_1 || '',
      city: `${order.billing?.postcode || ''} ${order.billing?.city || ''}`
    }
  },
  items: items,
  payment: {
    paid: order.status === 'completed' || order.date_paid != null,
    date: order.date_paid?.split('T')[0] || today,
    method: order.payment_method === 'cod' ? 'cash' : 'transfer'
  }
};

return [{ json: { skip: false, invoice } }];
